            return true;
        }
        if (obj == null) {
            return false;
        }
        if (getClass() != obj.getClass()) {
            return false;
        }
        final ExtraField other = (ExtraField) obj;
        return Objects.equals(subFields, other.subFields) && totalSize == other.totalSize;
    }

